149	impl syn::parse::Parse for Args {
150	    /// Parse macro arguments.
151	    ///
152	    /// ```no_run
153	    /// # use rust_i18n::i18n;
154	    /// # fn v1() {
155	    /// i18n!();
156	    /// # }
157	    /// # fn v2() {
158	    /// i18n!("locales");
159	    /// # }
160	    /// # fn v3() {
161	    /// i18n!("locales", fallback = "en");
162	    /// # }
163	    /// # fn v4() {
164	    /// i18n!("locales", fallback = ["en", "es"]);
165	    /// # }
166	    /// # fn v5() {
167	    /// i18n!("locales", fallback = ["en", "es"],
168	    ///       minify_key = true,
169	    ///       minify_key_len = 12,
170	    ///       minify_key_prefix = "t_",
171	    ///       minify_key_thresh = 64);
172	    /// # }
173	    /// ```
174	    ///
175	    /// Ref: https://docs.rs/syn/latest/syn/parse/index.html
176	    fn parse(input: syn::parse::ParseStream) -> syn::parse::Result<Self> {
177	        let lookahead = input.lookahead1();
178	        // The config from metadata is lower priority
179	
180	        let mut result = Self {
181	            locales_path: String::from("locales"),
182	            default_locale: None,
183	            fallback: None,
184	            extend: None,
185	            minify_key: DEFAULT_MINIFY_KEY,
186	            minify_key_len: DEFAULT_MINIFY_KEY_LEN,
187	            minify_key_prefix: DEFAULT_MINIFY_KEY_PREFIX.to_owned(),
188	            minify_key_thresh: DEFAULT_MINIFY_KEY_THRESH,
189	        };
190	
191	        result.load_metadata(input)?;
192	
193	        if lookahead.peek(LitStr) {
194	            result.consume_path(input)?;
195	
196	            if input.parse::<Token![,]>().is_ok() {
197	                result.consume_options(input)?;
198	            }
199	        } else if lookahead.peek(Ident) {
200	            result.consume_options(input)?;
201	        }
202	
203	        Ok(result)
204	    }
205	}
